    private static readonly Dictionary<string, GraphicsPath> Cache = [];

    public static bool Has(string id) => Paths.ContainsKey(id);

    /// <summary>Fill the provider's mark, fit and centred into <paramref name="dest"/>.</summary>
    public static bool Draw(Graphics g, string id, RectangleF dest, Color color)
    {
        if (!Cache.TryGetValue(id, out GraphicsPath? path))
        {
            if (!Paths.TryGetValue(id, out Mark mark)) return false;
            try { path = SvgPath.Parse(mark.Data, mark.Fill); }
            catch { return false; }
            Cache[id] = path;
        }

        float s = Math.Min(dest.Width, dest.Height) / 24f;
        GraphicsState state = g.Save();
        try
        {
            g.TranslateTransform(dest.X + (dest.Width - 24 * s) / 2, dest.Y + (dest.Height - 24 * s) / 2);
            g.ScaleTransform(s, s);
            using var brush = new SolidBrush(color);
            g.FillPath(brush, path);
        }
        finally { g.Restore(state); }
        return true;
    }
